  1→'use client';
  2→
  3→import { useState, useRef, useEffect, useCallback } from 'react';
  4→import Link from 'next/link';
  5→import s from './page.module.css';
  6→import { getSpeechRecognitionConstructor, type SpeechRecognitionInstance } from '@/lib/speechRecognition';
  7→
  8→// ── Types ──────────────────────────────────────────────────────────────────────
  9→
 10→type VoiceState = 'offline' | 'monitoring' | 'awake' | 'thinking' | 'grounded';
 11→
 12→interface HistoryMsg { role: 'user' | 'omega'; text: string; }
 13→
 14→interface RotatingPoints {
 15→  rotation: { y: number };
 16→}
 17→
 18→// ── PCM → WAV ──────────────────────────────────────────────────────────────────
 19→
 20→function buildWav(base64: string): string {
 21→  const binary = atob(base64);
 22→  const bytes = new Uint8Array(binary.length);
 23→  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
 24→  const hdr = new ArrayBuffer(44);
 25→  const v = new DataView(hdr);
 26→  v.setUint32(0, 0x52494646, false); v.setUint32(4, 36 + bytes.length, true);
 27→  v.setUint32(8, 0x57415645, false); v.setUint32(12, 0x666d7420, false);
 28→  v.setUint16(16, 16, true); v.setUint16(20, 1, true); v.setUint16(22, 1, true);
 29→  v.setUint32(24, 24000, true); v.setUint32(28, 48000, true);
 30→  v.setUint16(32, 2, true); v.setUint16(34, 16, true);
 31→  v.setUint32(36, 0x64617461, false); v.setUint32(40, bytes.length, true);
 32→  const blob = new Blob([hdr, bytes], { type: 'audio/wav' });
 33→  return URL.createObjectURL(blob);
 34→}
 35→
 36→// ── Main ───────────────────────────────────────────────────────────────────────
 37→
 38→export default function Home() {
 39→  const canvasRef       = useRef<HTMLDivElement>(null);
 40→  const recogRef        = useRef<SpeechRecognitionInstance | null>(null);
 41→  const audioRef        = useRef<HTMLAudioElement | null>(null);
 42→  const syncRef         = useRef<ReturnType<typeof setInterval> | null>(null);
 43→  const historyRef      = useRef<HistoryMsg[]>([]);
 44→  const rotSpeedRef     = useRef(0.0004);
 45→  const pointsRef       = useRef<RotatingPoints | null>(null);
 46→  const stateRef        = useRef<VoiceState>('offline');
 47→
 48→  const [started,        setStarted]        = useState(false);
 49→  const [voiceState,     setVoiceState]      = useState<VoiceState>('offline');
 50→  const [statusText,     setStatusText]      = useState('System Offline');
 51→  const [words,          setWords]           = useState<{ text: string; cls: string }[]>([{ text: 'Awaiting voice command...', cls: s.wordActive }]);
 52→  const [ripple,         setRipple]          = useState(false);
 53→  const [showDistill,    setShowDistill]     = useState(false);
 54→  const [showTheme,      setShowTheme]       = useState(false);
 55→  const [projection,     setProjection]      = useState('');
 56→  const [projectionVis,  setProjectionVis]   = useState(false);
 57→  const [canvasOpacity,  setCanvasOpacity]   = useState(0.3);
 58→
 59→  // keep stateRef in sync
 60→  const setState = useCallback((st: VoiceState) => {
 61→    stateRef.current = st;
 62→    setVoiceState(st);
 63→  }, []);
 64→
 65→  // ── Three.js particle field ──────────────────────────────────────────────────
 66→  useEffect(() => {
 67→    if (!started || !canvasRef.current) return;
 68→    let animId: number;
 69→
 70→    import('three').then(THREE => {
 71→      const scene    = new THREE.Scene();
 72→      const camera   = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
 73→      const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
 74→      renderer.setSize(window.innerWidth, window.innerHeight);
 75→      canvasRef.current!.appendChild(renderer.domElement);
 76→
 77→      const geo = new THREE.BufferGeometry();
 78→      const pos = new Float32Array(1500 * 3);
 79→      for (let i = 0; i < 4500; i++) pos[i] = (Math.random() - 0.5) * 12;
 80→      geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
 81→      const mat = new THREE.PointsMaterial({ color: 0x555555, size: 0.015 });
 82→      const pts = new THREE.Points(geo, mat);
 83→      pointsRef.current = pts;
 84→      scene.add(pts);
 85→      camera.position.z = 5;
 86→
 87→      const tick = () => {
 88→        animId = requestAnimationFrame(tick);
 89→        pts.rotation.y += rotSpeedRef.current;
 90→        renderer.render(scene, camera);
 91→      };
 92→      tick();
 93→
 94→      const onResize = () => {
 95→        camera.aspect = window.innerWidth / window.innerHeight;
 96→        camera.updateProjectionMatrix();
 97→        renderer.setSize(window.innerWidth, window.innerHeight);
 98→      };
 99→      window.addEventListener('resize', onResize);
100→      return () => {
101→        cancelAnimationFrame(animId);
102→        window.removeEventListener('resize', onResize);
103→        renderer.dispose();
104→      };
105→    });
106→
107→    return () => cancelAnimationFrame(animId);
108→  }, [started]);
109→
110→  // ── Speech recognition ───────────────────────────────────────────────────────
111→  function initSpeech() {
112→    const SR = getSpeechRecognitionConstructor();
113→    if (!SR) { setStatusText('API Unsupported'); return; }
114→
115→    const r = new SR();
116→    r.continuous = true;
117→    r.interimResults = true;
118→    r.lang = 'en-US';
119→    recogRef.current = r;
120→
121→    r.onstart = () => {
122→      if (stateRef.current === 'offline') {
123→        setState('monitoring');
124→        setStatusText('Monitoring...');
125→      }
126→    };
127→
128→    r.onresult = (event) => {
129→      let interim = '', final = '';
130→      for (let i = event.resultIndex; i < event.results.length; i++) {
131→        if (event.results[i].isFinal) final += event.results[i][0].transcript;
132→        else interim += event.results[i][0].transcript;
133→      }
134→      const full = (interim + final).toLowerCase();
135→
136→      if (stateRef.current === 'monitoring') {
137→        if (['hey omega', 'mega', 'hey mega'].some(w => full.includes(w))) {
138→          wakeUp();
139→          return;
140→        }
141→      }
142→      if (stateRef.current === 'awake' && audioRef.current && !audioRef.current.paused && interim.trim().length > 2) {
143→        stopSpeaking();
144→        setStatusText('Listening...');
145→      }
146→      if (stateRef.current === 'awake' && final.trim().length > 0) {
147→        handleInput(final.trim());
148→      }
149→    };
150→
151→    r.onerror = () => {};
152→    r.onend = () => { setTimeout(() => { try { r.start(); } catch { /* ignore */ } }, 100); };
153→    try { r.start(); } catch { /* ignore */ }
154→  }
155→
156→  // ── Wake ─────────────────────────────────────────────────────────────────────
157→  const wakeUp = useCallback(() => {
158→    setState('awake');
159→    setStatusText('Neural Link Active');
160→    setRipple(true);
161→    setWords([{ text: 'I am here.', cls: s.wordActive }]);
162→  }, [setState]);
163→
164→  // ── Stop speaking ─────────────────────────────────────────────────────────────
165→  const stopSpeaking = useCallback(() => {
166→    if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
167→    if (syncRef.current) { clearInterval(syncRef.current); syncRef.current = null; }
168→  }, []);
169→
170→  // ── Speak via /api/tts ────────────────────────────────────────────────────────
171→  const speak = useCallback(async (text: string) => {
172→    stopSpeaking();
