 13→  background-color: var(--void);
 14→  color: var(--accent);
 15→  font-family: 'Space Grotesk', sans-serif;
 16→  margin: 0;
 17→  overflow: hidden;
 18→  height: 100vh;
 19→  width: 100vw;
 20→  display: flex;
