 29→  top: 0; left: 0;
 30→  width: 100%; height: 100%;
 31→  z-index: 0;
 32→  opacity: 0.3;
 33→  transition: opacity 1s ease;
 34→}
 35→
 36→.startOverlay {
 37→  position: fixed;
 38→  inset: 0;
 39→  z-index: 100;
