  1→'use client';
  2→
  3→import { useCallback, useEffect, useRef, useState } from 'react';
  4→import {
  5→  getSpeechRecognitionConstructor,
  6→  type SpeechRecognitionInstance,
  7→  type SpeechRecognitionEventLike,
  8→  type SpeechRecognitionErrorEventLike,
  9→} from '@/lib/speechRecognition';
 10→
 11→export type VoiceState = 'dormant' | 'listening' | 'thinking' | 'speaking' | 'followup';
 12→
 13→export interface VoiceEngineOptions {
 14→  onTranscript: (text: string) => void;
 15→  onTTSStart?: () => void;
 16→  onTTSEnd?: () => void;
 17→  followUpWindowMs?: number;
 18→  ttsUrl?: string;
 19→  autoStart?: boolean;
 20→  useWhisper?: boolean;
 21→}
 22→
 23→export interface VoiceEngineReturn {
 24→  voiceState: VoiceState;
 25→  interim: string;
 26→  micLevel: number;
 27→  ttsLevel: number;
 28→  supported: boolean;
 29→  toggle: () => void;
 30→  speakText: (text: string) => Promise<void>;
 31→  stopSpeaking: () => void;
 32→  wakeUp: () => void;
 33→}
 34→
 35→const WAKE_WORDS = ['mega', 'omega'];
 36→const FOLLOW_UP_MS = 25_000;
 37→const MIN_SPEECH_CHARS = 3;
 38→const SILENCE_COMMIT_MS = 1400;
 39→
 40→// Shared helper: drive an audio level meter from an AnalyserNode
 41→function startLevelTick(
 42→  analyser: AnalyserNode,
 43→  setLevel: (v: number) => void,
 44→  animRef: React.MutableRefObject<number | null>,
 45→) {
 46→  const buf = new Uint8Array(analyser.frequencyBinCount);
 47→  const tick = () => {
 48→    analyser.getByteFrequencyData(buf);
 49→    const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
 50→    setLevel(Math.min(avg / 80, 1));
 51→    animRef.current = requestAnimationFrame(tick);
 52→  };
 53→  tick();
 54→}
 55→
 56→export function useVoiceEngine({
 57→  onTranscript,
 58→  onTTSStart,
 59→  onTTSEnd,
 60→  followUpWindowMs = FOLLOW_UP_MS,
 61→  ttsUrl = '/api/tts',
 62→  autoStart = true,
 63→  useWhisper = false,
 64→}: VoiceEngineOptions): VoiceEngineReturn {
 65→  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
 66→  const [interim, setInterim] = useState('');
 67→  const [micLevel, setMicLevel] = useState(0);
 68→  const [ttsLevel, setTtsLevel] = useState(0);
 69→  const [supported, setSupported] = useState(false);
 70→
 71→  const stateRef = useRef<VoiceState>('dormant');
 72→  const recogRef = useRef<SpeechRecognitionInstance | null>(null);
 73→  const followUpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
 74→  const audioCtxRef = useRef<AudioContext | null>(null);
 75→  const micStreamRef = useRef<MediaStream | null>(null);
 76→  const analyserRef = useRef<AnalyserNode | null>(null);
 77→  const micAnimRef = useRef<number | null>(null);
 78→  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
 79→  const ttsCtxRef = useRef<AudioContext | null>(null);
 80→  const ttsAnimRef = useRef<number | null>(null);
 81→  const mutedRef = useRef(false);
 82→  const restartTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 83→
 84→  // Whisper recording refs (only used when useWhisper=true)
 85→  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
 86→  const audioChunksRef = useRef<Blob[]>([]);
 87→  const silenceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 88→
 89→  // Stale-closure avoidance: callbacks read stateRef instead of voiceState
 90→  const setState = useCallback((s: VoiceState) => {
 91→    stateRef.current = s;
 92→    setVoiceState(s);
 93→  }, []);
 94→
 95→  // ── Shared AudioContext ────────────────────────────────────────────────────
 96→  const getAudioCtx = useCallback(() => {
 97→    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
 98→      audioCtxRef.current = new AudioContext();
 99→    }
100→    return audioCtxRef.current;
101→  }, []);
102→
103→  // ── Mic level analyzer ─────────────────────────────────────────────────────
104→  const startMicAnalyzer = useCallback(async () => {
105→    try {
106→      const ctx = getAudioCtx();
107→      if (!micStreamRef.current) {
108→        micStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
109→      }
110→      analyserRef.current?.disconnect();
111→      const src = ctx.createMediaStreamSource(micStreamRef.current);
112→      analyserRef.current = ctx.createAnalyser();
113→      analyserRef.current.fftSize = 128;
114→      src.connect(analyserRef.current);
115→      startLevelTick(analyserRef.current, setMicLevel, micAnimRef);
116→    } catch { /* mic denied */ }
117→  }, [getAudioCtx]);
118→
119→  const stopMicAnalyzer = useCallback(() => {
120→    if (micAnimRef.current) {
121→      cancelAnimationFrame(micAnimRef.current);
122→      micAnimRef.current = null;
123→      setMicLevel(0);
124→    }
125→  }, []);
126→
127→  // ── Follow-up window ──────────────────────────────────────────────────────
128→  const clearFollowUp = useCallback(() => {
129→    if (followUpTimer.current) clearTimeout(followUpTimer.current);
130→  }, []);
131→
132→  const enterFollowUp = useCallback(() => {
133→    setState('followup');
134→    clearFollowUp();
135→    followUpTimer.current = setTimeout(() => {
136→      if (stateRef.current === 'followup') setState('dormant');
137→    }, followUpWindowMs);
138→  }, [setState, clearFollowUp, followUpWindowMs]);
139→
140→  // ── TTS playback ──────────────────────────────────────────────────────────
141→  const stopSpeaking = useCallback(() => {
142→    ttsSourceRef.current?.stop();
143→    ttsSourceRef.current = null;
144→    if (ttsAnimRef.current) {
145→      cancelAnimationFrame(ttsAnimRef.current);
146→      ttsAnimRef.current = null;
147→    }
148→    // Close the dedicated TTS AudioContext to prevent leaks
149→    if (ttsCtxRef.current) {
150→      ttsCtxRef.current.close().catch(() => {});
151→      ttsCtxRef.current = null;
152→    }
153→    setTtsLevel(0);
154→  }, []);
155→
156→  const speakText = useCallback(async (text: string): Promise<void> => {
157→    if (!text?.trim()) { enterFollowUp(); return; }
158→    stopSpeaking();
159→    setState('speaking');
160→    onTTSStart?.();
161→
162→    try {
163→      const res = await fetch(ttsUrl, {
164→        method: 'POST',
165→        headers: { 'Content-Type': 'application/json' },
166→        body: JSON.stringify({ text: text.slice(0, 2000) }),
167→      });
168→      const data = await res.json();
169→
170→      if (!data.audio) throw new Error('No audio returned');
171→
172→      const raw = atob(data.audio);
173→      const bytes = new Uint8Array(raw.length);
174→      for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
175→
176→      // Dedicated context for TTS — tracked in ttsCtxRef for cleanup
177→      const ctx = new AudioContext();
178→      ttsCtxRef.current = ctx;
179→      const buffer = await ctx.decodeAudioData(bytes.buffer);
180→
181→      const analyser = ctx.createAnalyser();
182→      analyser.fftSize = 128;
183→
184→      const src = ctx.createBufferSource();
185→      src.buffer = buffer;
186→      src.connect(analyser);
187→      analyser.connect(ctx.destination);
188→      ttsSourceRef.current = src;
189→
190→      startLevelTick(analyser, setTtsLevel, ttsAnimRef);
191→
192→      src.start();
193→      src.onended = () => {
194→        if (ttsAnimRef.current) cancelAnimationFrame(ttsAnimRef.current);
195→        ttsAnimRef.current = null;
196→        setTtsLevel(0);
197→        ctx.close().catch(() => {});
198→        ttsCtxRef.current = null;
199→        onTTSEnd?.();
200→        enterFollowUp();
201→      };
202→    } catch (e) {
203→      console.warn('[VoiceEngine] TTS error:', e);
204→      onTTSEnd?.();
205→      enterFollowUp();
206→    }
207→  }, [ttsUrl, stopSpeaking, setState, enterFollowUp, onTTSStart, onTTSEnd]);
208→
209→  // ── Speech recognition ────────────────────────────────────────────────────
210→  const stopRecognition = useCallback(() => {
211→    try { recogRef.current?.stop(); } catch { /* ignore */ }
212→  }, []);
213→
214→  const startRecognition = useCallback(() => {
215→    const SR = getSpeechRecognitionConstructor();
216→    if (!SR) return;
217→
218→    stopRecognition();
219→
220→    const r = new SR();
221→    r.continuous = true;
222→    r.interimResults = true;
223→    r.lang = 'en-US';
224→    r.maxAlternatives = 1;
225→    recogRef.current = r;
226→
227→    let finalBuffer = '';
